CREATE DATABASE IF NOT EXISTS aic_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE aic_db;

CREATE TABLE users (
    id            INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    user_id_str   VARCHAR(64)  NOT NULL UNIQUE,
    password_hash VARCHAR(256) NOT NULL,
    role          ENUM('student','teacher','admin') NOT NULL,
    name          VARCHAR(128) NOT NULL,
    email         VARCHAR(256),
    created_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at    DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_role (role)
) ENGINE=InnoDB;

CREATE TABLE classes (
    id          INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    class_code  VARCHAR(32)  NOT NULL UNIQUE,
    class_name  VARCHAR(256) NOT NULL,
    teacher_id  INT UNSIGNED NOT NULL,
    semester    VARCHAR(32),
    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (teacher_id) REFERENCES users(id) ON DELETE RESTRICT
) ENGINE=InnoDB;

CREATE TABLE class_enrollments (
    id          INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    class_id    INT UNSIGNED NOT NULL,
    student_id  INT UNSIGNED NOT NULL,
    enrolled_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (class_id)   REFERENCES classes(id) ON DELETE CASCADE,
    FOREIGN KEY (student_id) REFERENCES users(id)   ON DELETE CASCADE,
    UNIQUE KEY uq_enrollment (class_id, student_id)
) ENGINE=InnoDB;

CREATE TABLE assignments (
    id           INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    class_id     INT UNSIGNED NOT NULL,
    title        VARCHAR(512) NOT NULL,
    description  TEXT,
    course_code  VARCHAR(32),
    due_date     DATETIME,
    created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (class_id) REFERENCES classes(id) ON DELETE CASCADE,
    INDEX idx_class (class_id)
) ENGINE=InnoDB;

CREATE TABLE submissions (
    id              INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    assignment_id   INT UNSIGNED NOT NULL,
    student_id      INT UNSIGNED NOT NULL,
    chatgpt_before  MEDIUMTEXT NOT NULL,
    user_prompt     MEDIUMTEXT NOT NULL,
    essay           MEDIUMTEXT NOT NULL,
    submitted_at    DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (assignment_id) REFERENCES assignments(id) ON DELETE CASCADE,
    FOREIGN KEY (student_id)    REFERENCES users(id)       ON DELETE CASCADE,
    UNIQUE KEY uq_submission (assignment_id, student_id),
    INDEX idx_student (student_id)
) ENGINE=InnoDB;

CREATE TABLE metrics (
    id                    INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    submission_id         INT UNSIGNED NOT NULL UNIQUE,
    pi_score              TINYINT UNSIGNED,
    ui_score              TINYINT UNSIGNED,
    oi_score              TINYINT UNSIGNED,
    aic_score             TINYINT UNSIGNED,
    topic_score           TINYINT UNSIGNED,
    weight_pi             FLOAT,
    weight_ui             FLOAT,
    weight_oi             FLOAT,
    pi_depth_tokens       INT,
    pi_depth_norm         FLOAT,
    pi_critical_ratio     FLOAT,
    pi_avg_sent_len       FLOAT,
    pi_ttr                FLOAT,
    pi_complexity         FLOAT,
    ui_cos_similarity     FLOAT,
    ui_distance           FLOAT,
    ui_newinfo_ratio      FLOAT,
    oi_topic_score_raw    FLOAT,
    embedding_backend     VARCHAR(16),
    computed_at           DATETIME,
    FOREIGN KEY (submission_id) REFERENCES submissions(id) ON DELETE CASCADE
) ENGINE=InnoDB;

CREATE TABLE analysis_jobs (
    id              INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    job_uuid        CHAR(36) NOT NULL UNIQUE,
    submission_id   INT UNSIGNED NOT NULL,
    status          ENUM('pending','running','done','failed') DEFAULT 'pending',
    error_message   TEXT,
    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
    started_at      DATETIME,
    completed_at    DATETIME,
    FOREIGN KEY (submission_id) REFERENCES submissions(id) ON DELETE CASCADE,
    INDEX idx_status (status)
) ENGINE=InnoDB;

CREATE TABLE analysis_run_metadata (
    id                       INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    job_id                   INT UNSIGNED NOT NULL UNIQUE,
    metric_version           VARCHAR(64),
    baseline_version         VARCHAR(64),
    optimized_version        VARCHAR(64),
    processed_count          INT,
    total_runtime_ms         FLOAT,
    baseline_runtime_ms      FLOAT,
    runtime_delta_pct        FLOAT,
    memory_peak_kb           FLOAT,
    baseline_memory_peak_kb  FLOAT,
    memory_delta_pct         FLOAT,
    baseline_scores          JSON,
    stage_runtimes_ms        JSON,
    score_deltas             JSON,
    quality_passed           BOOLEAN,
    bootstrap_passed         BOOLEAN,
    measured_at              DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (job_id) REFERENCES analysis_jobs(id) ON DELETE CASCADE,
    INDEX idx_measured_at (measured_at)
) ENGINE=InnoDB;

CREATE TABLE teacher_feedback (
    id              INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    assignment_id   INT UNSIGNED NOT NULL,
    student_id      INT UNSIGNED NOT NULL,
    teacher_id      INT UNSIGNED NOT NULL,
    content         TEXT NOT NULL,
    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (assignment_id) REFERENCES assignments(id) ON DELETE CASCADE,
    FOREIGN KEY (student_id)    REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (teacher_id)    REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE KEY uq_feedback (assignment_id, student_id)
) ENGINE=InnoDB;

